console.log("DropIt Background Service Worker initialized");chrome.runtime.onInstalled.addListener(e=>{e.reason==="install"?console.log("DropIt installed for the first time"):e.reason==="update"&&console.log("DropIt updated to version:",chrome.runtime.getManifest().version)});chrome.runtime.onMessage.addListener((e,t,o)=>{switch(console.log("Background received message:",e),e.type){case"GET_TAB_INFO":return t.tab&&o({title:t.tab.title,url:t.tab.url,id:t.tab.id}),!0;default:return!1}});
